const CryptoJS = require('crypto-js')

function get_response(e) {
    const ju = "asdASE123854kjsd"
    const Og = CryptoJS.enc.Utf8.parse(ju)
        , GA = CryptoJS.enc.Utf8.parse(ju)
        , Lg = {
            iv: GA,
            mode: CryptoJS.mode.CBC,
            padding: CryptoJS.pad.Pkcs7
        };
    const t = CryptoJS.enc.Hex.parse(e)
        , n = CryptoJS.enc.Base64.stringify(t)
        , o = CryptoJS.AES.decrypt(n, Og, Lg).toString(CryptoJS.enc.Utf8);
    return JSON.parse(o.toString())
}


let data = ""
console.log(get_response(data));
